import org.springframework.beans.factory.annotation.Value;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import javax.servlet.ServletContext;
import java.io.File;
import java.io.IOException;
import java.net.MalformedURLException;
import java.net.URL;

@RestController
public class FileUploadController {

    @Value("${uploadDir}")
    private String uploadFolder;

    @PostMapping("/upload")
    public String upload(@RequestParam("file") MultipartFile file, ServletContext servletContext) {
        String fileName = file.getOriginalFilename();
        String absolutePath = servletContext.getRealPath(uploadFolder);

        File uploadDir = new File(absolutePath);
        if (!uploadDir.exists()) {
            uploadDir.mkdirs();
        }

        try {
            file.transferTo(new File(uploadDir + "/" + fileName));
            return servletContext.getContextPath() +  uploadFolder + "/" + fileName;
        } catch (IOException e) {
            e.printStackTrace();
        }

        return "Fail!";
    }
}